  ('medical-tech-moex-20638', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關胰臟假性囊腫 (pseudocyst) 的敘述，何者正確？ 是一種惡性囊性腫瘤    是急性胰臟炎的併發症 囊腫內壁覆蓋單層柱狀上皮  囊腫內含有毛髮及皮脂性物質', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20639', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關膽囊癌的敘述，何者正確？ 阻塞性黃疸是主要的臨床表現  常與膽結石與慢性膽囊炎有關 多數是鱗狀細胞癌    預後很好，五年存活率90%', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 58, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20640', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關病毒性肝炎的敘述，何者正確？ A型肝炎會變成慢性肝炎  B型肝炎病毒是一種DNA病毒 D型肝炎只會伴隨C型肝炎患者發生  E型肝炎主要是經由血液傳染', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20641', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列何種癌症與所列病原體的相關性最小？ 肝癌－B型肝炎病毒 (Hepatitis B virus)  胃癌－螺旋桿菌 (Helicobacter) 子宮頸癌－人類乳頭瘤病毒 (Human papilloma virus)  陰道癌－陰道滴蟲 (Trichomonas vaginalis)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20642', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '一名五個月大嬰兒有嚴重腹脹，直腸切片檢查發現病變區沒有神經元細胞的存在。嬰兒最可能患有下列何 種疾病？  腸套疊    憩室症    肛門閉鎖    巨腸症 (megacolon)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20643', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '急性化膿性骨髓炎 (acute purulent osteomyelitis) 是由何種病原體所引起？ 黴菌  細菌  病毒  寄生蟲', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20644', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關硬腦下出血 (subdural hematoma) 的敘述，何者不正確？ 可分急性與慢性兩種    急性硬腦膜下出血多有明顯外傷病史 慢性硬腦膜下出血有時查不出外傷病史  多因為中硬腦膜動脈出血', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 63, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20645', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '腦下垂腺生長激素細胞瘤若引起病人產生巨人症 (gigantism)，則病人的年紀多在： 20歲以下  21~40歲  41~60歲  61歲以上', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20646', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '橫紋肌肉瘤 (rhabdomyosarcoma) 最好發的位置是： 頭頸部  心臟  後腹腔  下肢', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 65, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20647', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關經幕腦疝 (transtentorial herniation) 的敘述，何者錯誤？ 病灶多在一側的大腦半球   顳葉內側下部脫出超過小腦鐮 上部腦幹會被壓迫，第七對腦神經首先受影響  後大腦動脈分支也會被壓迫，而造成枕葉之梗塞', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 66, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
